        0x0000040602A03014UL, 0x0000080602803015UL, 0x0000040602E03016UL, 0x0000080602C03017UL,
        0x0000040603203018UL, 0x0000080603003019UL, 0x000004060360301AUL, 0x000008060340301BUL,
        0x0000041FCB40FE59UL, 0x0000081FCB20FE5AUL, 0x0000041FCB80FE5BUL, 0x0000081FCB60FE5CUL,
        0x0000041FCBC0FE5DUL, 0x0000081FCBA0FE5EUL, 0x0000041FE120FF08UL, 0x0000081FE100FF09UL,
        0x0000041FE7A0FF3BUL, 0x0000081FE760FF3DUL, 0x0000041FEBA0FF5BUL, 0x0000081FEB60FF5DUL,
        0x0000041FEC00FF5FUL, 0x0000081FEBE0FF60UL, 0x0000041FEC60FF62UL, 0x0000081FEC40FF63UL,
    ];

    public static BidiClass GetClass(int codePoint)
    {
        ReadOnlySpan<ulong> records = ClassRanges;
        int low = 0;
        int high = records.Length - 1;
        while (low <= high)
        {
            int middle = low + ((high - low) >> 1);
            ulong record = records[middle];
            int start = (int)(record & CodePointMask);
            int end = (int)((record >> CodePointBits) & CodePointMask);
            if (codePoint < start) high = middle - 1;
            else if (codePoint > end) low = middle + 1;
            else return (BidiClass)(record >> (CodePointBits * 2));
        }
        return BidiClass.L;
    }

    public static bool TryGetBracket(int codePoint, out int pair, out BracketKind kind)
    {
        ReadOnlySpan<ulong> records = BracketRecords;
        int low = 0;
        int high = records.Length - 1;
        while (low <= high)
        {
            int middle = low + ((high - low) >> 1);
            ulong record = records[middle];
            int candidate = (int)(record & CodePointMask);
            if (codePoint < candidate) high = middle - 1;
            else if (codePoint > candidate) low = middle + 1;
            else
            {
                pair = (int)((record >> CodePointBits) & CodePointMask);
                kind = (BracketKind)(record >> (CodePointBits * 2));
                return true;
            }
        }
        pair = 0;
        kind = BracketKind.None;
        return false;
    }
}
